import anthropic
import json

client = anthropic.Anthropic()

# Tool definitions are large and never change between requests.
# Embed them in the system prompt as a cached block.
TOOLS_DESCRIPTION = json.dumps([
    {
        "name": "search_codebase",
        "description": "Search the repository for files matching a query. Returns file paths and snippets.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search terms or regex pattern"},
                "file_extension": {"type": "string", "description": "Filter by extension, e.g. .py"},
                "max_results": {"type": "integer", "default": 10},
            },
            "required": ["query"],
        },
    },
    {
        "name": "read_file",
        "description": "Read the full content of a file by its path.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string"},
            },
            "required": ["path"],
        },
    },
    {
        "name": "write_file",
        "description": "Write or overwrite a file with the given content.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string"},
                "content": {"type": "string"},
            },
            "required": ["path", "content"],
        },
    },
], indent=2)

SYSTEM = [
    {
        "type": "text",
        "text": (
            "You are a coding assistant with access to the following tools.\n\n"
            "Available tools (JSON schema):\n" + TOOLS_DESCRIPTION + "\n\n"
            "Always prefer reading existing code before making changes. "
            "Confirm your understanding of the task before writing files."
        ),
        "cache_control": {"type": "ephemeral"},
    }
]

def agent_call(user_message: str):
    return client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        system=SYSTEM,
        messages=[{"role": "user", "content": user_message}],
        tools=[
            # The tools parameter still needs the real tool definitions for routing,
            # but the system prompt already has them cached for model comprehension.
            # Alternatively, mark the tools list itself for caching — see note below.
        ],
    )

# ──────────────────────────────────────────────────────────────────────────
# NOTE: You can also cache via the tools parameter directly by passing
# cache_control on the LAST tool definition:
#
# tools = [
#     {"name": "search_codebase", ...},
#     {"name": "read_file", ...},
#     {
#         "name": "write_file",
#         ...,
#         "cache_control": {"type": "ephemeral"},  # caches all tools above this point
#     },
# ]
# ──────────────────────────────────────────────────────────────────────────
